& 𝙀𝙣𝙫𝙞𝙧𝙤𝙣𝙢𝙚𝙣𝙩 𝙈𝙖𝙣𝙖𝙜𝙚𝙧'𝙨\n*Internal/External audit\n*Failed monthly operational test standards (Water and air quality)\n*Customer safety\n\nI can go on and on about this, i'd love to share my experiences with you.", "addressCountryOnly": "Thailand", "addressWithCountry": "Bangkok, Bangkok City, Thailand", "addressWithoutCountry": "Bangkok, Bangkok City", "companyIndustry": "Hospitality", "companyLinkedin": "https://www.linkedin.com/company/floral-hotel-supply/", "companyName": "Floral Hotel Supply", "companySize": "201-500", "companyWebsite": "http://www.floralhotelsupply.com", "connections": "17", "email": "pariwat.p@floralhotelsupply.com", "experiences/0/companyId": "6454617", "experiences/0/companyIndustry": "Hospitality", "experiences/0/companyLink1": "https://www.linkedin.com/company/floral-hotel-supply/", "experiences/0/companyName": "Floral Hotel Supply", "experiences/0/companySize": "201-500", "experiences/0/companyUrn": "urn:li:fsd_company:6454617", "experiences/0/companyWebsite": "http://www.floralhotelsupply.com", "experiences/0/employmentType": "Full-time", "experiences/0/jobLocationCountry": "TH", "experiences/0/jobStartedOn": "2020", "experiences/0/jobStillWorking": "true", "experiences/0/logo": "https://media.licdn.com/dms/image/v2/C510BAQEljPOjE0DlKw/company-logo_400_400/company-logo_400_400/0/1630589794812/floral_hotel_supply_logo?e=1778112000&v=beta&t=_3iA777NS4sJsCaLzfn33KUc54xeMvNFopz7jz7w31U", "experiences/0/title": "General Manager", "experiences/1/companyId": "6454617", "experiences/1/companyIndustry": "Hospitality", "experiences/1/companyLink1": "https://www.linkedin.com/company/floral-hotel-supply/", "experiences/1/companyName": "Floral Hotel Supply", "experiences/1/companySize": "201-500", "experiences/1/companyUrn": "urn:li:fsd_company:6454617", "experiences/1/companyWebsite": "http://www.floralhotelsupply.com", "experiences/1/employmentType": "Full-time", "experiences/1/jobLocationCountry": "TH", "experiences/1/jobStartedOn": "2012", "expe